        const newStartBtn = startBtn.cloneNode(true);
        startBtn.parentNode.replaceChild(newStartBtn, startBtn);

        newStartBtn.addEventListener("click", closeDialog);

        introDialog.addEventListener(
            "click",
            (e) => {
                if (e.target === introDialog) {
                    closeDialog();
